# Simple ablation: compare three variants on a small eval set
async def ablation_test(question, retriever, llm, ground_truth):
    broad_q = await step_back_chain.ainvoke({"question": question})

    # Retrieve
    specific_docs, broad_docs = await asyncio.gather(
        retriever.ainvoke(question),
        retriever.ainvoke(broad_q),
    )

    def answer_with(ctx_docs, label):
        ctx = "\n\n".join(f"[{i+1}] {d.page_content}" for i, d in enumerate(ctx_docs))
        return (answer_prompt | llm | StrOutputParser()).invoke({
            "context": ctx, "question": question
        }), label

    results = {
        "specific_only": answer_with(specific_docs, "specific")[:2],
        "broad_only":    answer_with(broad_docs, "broad")[:2],
        "combined":      answer_with(broad_docs[:2] + specific_docs, "combined")[:2],
    }

    # Compare to ground truth manually or with RAGAS answer_correctness
    for variant, (ans, lbl) in results.items():
        print(f"[{variant}] {ans[:120]}...")
